public boolean equals(Object other) {
        boolean ret;

        if (this == other) { 
            ret = true;
        } else if (other == null) {
            ret = false;
        } else  {
            try {
                Complex rhs = (Complex)other;
                if (rhs.isNaN()) {
                    ret = this.isNaN();
                } else {
                    ret = (this.real == rhs.getReal()) && (this.imaginary == rhs.getImaginary());
                }
            } catch (ClassCastException ex) {
                // ignore exception
                ret = false;
            }
        }

        return ret;
    }

